use anyhow::Result;
use clap::Parser;

mod rust_dispatcher;
mod rustdoc;
mod typescript;

#[derive(Parser)]
#[command(
    name = "truapi-codegen",
    about = "Generate TS client from TrUAPI Rust traits"
)]
struct Cli {
    /// Path to rustdoc JSON file (generated by `cargo +nightly rustdoc -p truapi --output-format json`)
    #[arg(short, long)]
    input: String,

    /// Output directory for generated files
    #[arg(short, long, default_value = "generated")]
    output: String,

    /// Output directory for the generated Rust dispatcher (optional).
    #[arg(long)]
    rust_output: Option<String>,
}

fn main() -> Result<()> {
    let cli = Cli::parse();
    let json = std::fs::read_to_string(&cli.input)?;
    let krate = rustdoc::parse(&json)?;
    let api = rustdoc::extract_api(&krate)?;
    typescript::generate(&api, &cli.output)?;
    println!("Generated TypeScript client in {}", cli.output);
    if let Some(path) = &cli.rust_output {
        rust_dispatcher::generate(&api, path)?;
        println!("Generated Rust dispatcher in {}", path);
    }
    Ok(())
}
